INSERT INTO [dbo].[tInstitutionResourceAudit] ([iInstitutionId], [iResourceId], [iInstitutionResourceAuditTypeId], [iLicenseCount], [decSingleLicensePrice], [vchCreatorId], [dtCreationDate],
	[vchEventDescription], [bLegacy])
